import{_ as c,o as a,c as o,a3 as t}from"./chunks/framework.aYYe0dfI.js";const u=JSON.parse('{"title":"Module extract:cache","description":"extract:cache 模块是 clore::extract 中负责提取结果缓存的持久化与失效管理子系统。它提供了一组正交的公开操作：通过 build_cache_key 和 build_compile_signature 生成标准化的缓存键与编译签名；利用 capture_dependency_snapshot 和 dependencies_changed 捕获当前依赖状态并判断是否过期；以 load_extract_cache / save_extract_cache 和 load_clice_cache / save_clice_cache 分别支持简单的整数值缓存和完整的 Clice 工作区缓存数据的存储与加载。此外，hash_file 用于计算文件内容的哈希值以支撑依赖追踪，split_cache_key 可将组合键解析为组成部分供外部检查。这些函数共同构成了一个既可独立使用又可组合的缓存工具集，调用者需自行处理返回的 CacheError 以保证缓存一致性。","frontmatter":{"title":"Module extract:cache","description":"extract:cache 模块是 clore::extract 中负责提取结果缓存的持久化与失效管理子系统。它提供了一组正交的公开操作：通过 build_cache_key 和 build_compile_signature 生成标准化的缓存键与编译签名；利用 capture_dependency_snapshot 和 dependencies_changed 捕获当前依赖状态并判断是否过期；以 load_extract_cache / save_extract_cache 和 load_clice_cache / save_clice_cache 分别支持简单的整数值缓存和完整的 Clice 工作区缓存数据的存储与加载。此外，hash_file 用于计算文件内容的哈希值以支撑依赖追踪，split_cache_key 可将组合键解析为组成部分供外部检查。这些函数共同构成了一个既可独立使用又可组合的缓存工具集，调用者需自行处理返回的 CacheError 以保证缓存一致性。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/extract/cache.md","filePath":"zh/clore/modules/extract/cache.md"}'),r={name:"zh/clore/modules/extract/cache.md"};function d(i,e,l,s,h,n){return a(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="module-extract-cache" tabindex="-1">Module <code>extract:cache</code> <a class="header-anchor" href="#module-extract-cache" aria-label="Permalink to &quot;Module `extract:cache`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p><code>extract:cache</code> 模块是 <code>clore::extract</code> 中负责提取结果缓存的持久化与失效管理子系统。它提供了一组正交的公开操作：通过 <code>build_cache_key</code> 和 <code>build_compile_signature</code> 生成标准化的缓存键与编译签名；利用 <code>capture_dependency_snapshot</code> 和 <code>dependencies_changed</code> 捕获当前依赖状态并判断是否过期；以 <code>load_extract_cache</code> / <code>save_extract_cache</code> 和 <code>load_clice_cache</code> / <code>save_clice_cache</code> 分别支持简单的整数值缓存和完整的 Clice 工作区缓存数据的存储与加载。此外，<code>hash_file</code> 用于计算文件内容的哈希值以支撑依赖追踪，<code>split_cache_key</code> 可将组合键解析为组成部分供外部检查。这些函数共同构成了一个既可独立使用又可组合的缓存工具集，调用者需自行处理返回的 <code>CacheError</code> 以保证缓存一致性。</p><p>在内部实现上，模块定义了多个用于序列化的数据结构（如 <code>SerializedCacheData</code>、<code>SerializedDependencySnapshot</code>），并采用多线程并行方式（通过 <code>DependencyHashTaskResult</code> 和并行阈值）加速依赖快照的捕获。缓存路径的确定、临时文件写入与原子重命名（如 <code>make_unique_tmp_path</code>）等细节被封装在匿名命名空间函数中，确保公开接口的简洁性与正确性。无论是用于提取流水线的增量更新，还是用于 Clice 工作区缓存的一致性校验，该模块都承担了缓存生命周期管理的核心逻辑。</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./ast"><code>extract:ast</code></a></li><li><a href="./compiler"><code>extract:compiler</code></a></li><li><a href="./scan"><code>extract:scan</code></a></li><li><code>std</code></li><li><a href="./../support/"><code>support</code></a></li></ul><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-extract-cache-cacheerror" tabindex="-1"><code>clore::extract::cache::CacheError</code> <a class="header-anchor" href="#clore-extract-cache-cacheerror" aria-label="Permalink to &quot;`clore::extract::cache::CacheError`&quot;">​</a></h3><p>Declaration: <code>extract/cache.cppm:20</code></p><p>Definition: <code>extract/cache.cppm:20</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/cache/"><code>Namespace clore::extract::cache</code></a></p><p><code>CacheError</code> 是一个简单的值类型，其唯一的数据成员 <code>message</code> 类型为 <code>std::string</code>，用于存储错误描述。该结构依赖编译器隐式生成的特殊成员函数（默认构造函数、拷贝构造函数、移动构造函数、拷贝赋值运算符、移动赋值运算符与析构函数），这些函数对 <code>message</code> 执行对应的浅层或移动语义操作。由于未定义额外的不变量，<code>CacheError</code> 的构造与赋值行为完全由 <code>std::string</code> 的接口决定，内部状态仅受 <code>message</code> 内容的合法性约束。</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>The <code>message</code> member must be set to a descriptive error string when an error occurs.</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>message</code>: a <code>std::string</code> that stores the error description.</li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Can be thrown as an exception or returned as an error result in cache-related functions.</li></ul><h3 id="clore-extract-cache-cachekeyparts" tabindex="-1"><code>clore::extract::cache::CacheKeyParts</code> <a class="header-anchor" href="#clore-extract-cache-cachekeyparts" aria-label="Permalink to &quot;`clore::extract::cache::CacheKeyParts`&quot;">​</a></h3><p>Declaration: <code>extract/cache.cppm:24</code></p><p>Definition: <code>extract/cache.cppm:24</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/cache/"><code>Namespace clore::extract::cache</code></a></p><p>实现中，<code>clore::extract::cache::CacheKeyParts</code> 是一个平凡的聚合结构体，其内部仅由两个公开数据成员组成：<code>std::string path</code> 用于存放资源路径，以及 <code>std::uint64_t compile_signature</code> 用于存放编译签名。该结构体没有定义任何构造函数、析构函数或运算符重载，完全依赖默认的复制、移动及比较语义。因此，它的生命周期管理和值传递行为完全由编译器生成的成员函数处理，不隐含任何额外的不变式约束；所有对等判别或哈希计算均需要由外部逻辑实现。这种设计使得结构体在作为缓存键的组成部分时保持轻量，并允许调用方按成员顺序直接进行初始化或构造。</p><h4 id="invariants-1" tabindex="-1">Invariants <a class="header-anchor" href="#invariants-1" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>No explicit invariants documented; likely expects <code>path</code> to be a valid file path and <code>compile_signature</code> to be non-zero? Not confirmed.</li></ul><h4 id="key-members-1" tabindex="-1">Key Members <a class="header-anchor" href="#key-members-1" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>std::string path</code></li><li><code>std::uint64_t compile_signature</code></li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to uniquely identify cache entries based on a file and its compile-time signature.</li></ul><h3 id="clore-extract-cache-cacherecord" tabindex="-1"><code>clore::extract::cache::CacheRecord</code> <a class="header-anchor" href="#clore-extract-cache-cacherecord" aria-label="Permalink to &quot;`clore::extract::cache::CacheRecord`&quot;">​</a></h3><p>Declaration: <code>extract/cache.cppm:36</code></p><p>Definition: <code>extract/cache.cppm:36</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/cache/"><code>Namespace clore::extract::cache</code></a></p><p><code>clore::extract::cache::CacheRecord</code> 的核心职责是将一次完整提取操作的所有可缓存状态聚合为单一记录，以便序列化、反序列化以及后续的失效判断。其内部字段可划分为校验元数据与提取结果两部分：<code>compile_signature</code> 和 <code>source_hash</code> 分别记录编译环境签名和源文件的哈希值，用于快速判定缓存是否过期；<code>ast_deps</code>、<code>scan</code> 和 <code>ast</code> 则依次保存依赖快照、扫描结果以及最终的 AST 结果。关键的不变量要求：当 <code>source_hash</code> 或 <code>compile_signature</code> 在加载时与当前计算值不匹配时，整条记录必须视为无效，其余字段的内容不得用于后续编译流程。成员初始化顺序与声明顺序一致，所有可平凡复制的整数成员被显式零初始化，而复合类型成员则通过默认构造保持空状态，从而保证一个默认构造的 <code>CacheRecord</code> 始终处于“完全失效”的基态。</p><h4 id="invariants-2" tabindex="-1">Invariants <a class="header-anchor" href="#invariants-2" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>Fields are default-initialized to zero or default-constructed.</li><li><code>source_hash</code> and <code>compile_signature</code> are expected to be non-zero after a successful extraction.</li><li><code>ast_deps</code>, scan, and ast hold consistent results from the same extraction.</li></ul><h4 id="key-members-2" tabindex="-1">Key Members <a class="header-anchor" href="#key-members-2" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>compile_signature</code></li><li><code>source_hash</code></li><li><code>ast_deps</code></li><li>scan</li><li>ast</li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Populated by the extraction pipeline after a successful extraction.</li><li>Retrieved by the cache module to return cached results.</li><li>Stored in a cache container keyed by source hash and compile signature.</li></ul><h3 id="clore-extract-cache-clicecachedata" tabindex="-1"><code>clore::extract::cache::CliceCacheData</code> <a class="header-anchor" href="#clore-extract-cache-clicecachedata" aria-label="Permalink to &quot;`clore::extract::cache::CliceCacheData`&quot;">​</a></h3><p>Declaration: <code>extract/cache.cppm:68</code></p><p>Definition: <code>extract/cache.cppm:68</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/cache/"><code>Namespace clore::extract::cache</code></a></p><p>结构体 <code>clore::extract::cache::CliceCacheData</code> 是缓存系统的核心数据容器，内部由三个 <code>std::vector</code> 成员构成：<code>paths</code> 存储文件路径字符串，<code>pch</code> 与 <code>pcm</code> 分别持有与路径对应的预编译头缓存条目和预编译模块缓存条目。这三个向量通过隐式的索引关联保持同步：对于任意有效索引 <code>i</code>，<code>paths[i]</code>、<code>pch[i]</code> 与 <code>pcm[i]</code> 共同描述同一个编译单元的缓存状态。不变量要求所有向量长度始终相等，且 <code>pch</code> 与 <code>pcm</code> 中的条目必须与 <code>paths</code> 中的路径一一对应，读取或写入操作需确保此同步关系不被破坏。</p><h4 id="invariants-3" tabindex="-1">Invariants <a class="header-anchor" href="#invariants-3" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li><code>paths</code>、<code>pch</code>、<code>pcm</code> 中的各个字段是相互独立的向量</li><li>无显式的不变式约束</li></ul><h4 id="key-members-3" tabindex="-1">Key Members <a class="header-anchor" href="#key-members-3" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>paths</code></li><li><code>pch</code></li><li><code>pcm</code></li></ul><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>作为缓存系统的一部分，存储提取的文件路径和对应的编译产物数据</li><li>可能由缓存填充逻辑写入，由读取逻辑遍历并使用</li></ul><h3 id="clore-extract-cache-clicecachedepentry" tabindex="-1"><code>clore::extract::cache::CliceCacheDepEntry</code> <a class="header-anchor" href="#clore-extract-cache-clicecachedepentry" aria-label="Permalink to &quot;`clore::extract::cache::CliceCacheDepEntry`&quot;">​</a></h3><p>Declaration: <code>extract/cache.cppm:46</code></p><p>Definition: <code>extract/cache.cppm:46</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/cache/"><code>Namespace clore::extract::cache</code></a></p><p><code>clore::extract::cache::CliceCacheDepEntry</code> 的实现是一个极简的聚合体，仅包含两个整数成员：<code>path</code>（<code>std::uint32_t</code> 类型，默认值为 <code>0</code>）和 <code>hash</code>（<code>std::uint64_t</code> 类型，默认值为 <code>0</code>）。这种布局直接呼应其文档声明的目的——与 <code>clice/src/server/workspace.cpp</code> 中的 <code>CacheData</code> 保持模式兼容。因此，该结构体未定义任何自定义构造函数、析构函数或赋值运算符，完全依赖编译器生成的默认实现，以确保其对象表示（包括成员顺序、对齐和填充）与外部缓存格式精确匹配。两个成员均初始化为 <code>0</code>，这在内部被用作“空”或“未使用”依存条目的哨兵值，任何有效条目必须至少设置 <code>path</code> 或 <code>hash</code> 中的一个非零值。</p><h4 id="invariants-4" tabindex="-1">Invariants <a class="header-anchor" href="#invariants-4" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>Fields are default-initialized to zero.</li><li>The struct layout is compatible with an external <code>CacheData</code> schema.</li></ul><h4 id="key-members-4" tabindex="-1">Key Members <a class="header-anchor" href="#key-members-4" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>path</code></li><li><code>hash</code></li></ul><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used in clice workspace cache structures for dependency tracking.</li><li>Serialized or interpreted in a schema-compatible manner with <code>CacheData</code>.</li></ul><h3 id="clore-extract-cache-clicecachepchentry" tabindex="-1"><code>clore::extract::cache::CliceCachePCHEntry</code> <a class="header-anchor" href="#clore-extract-cache-clicecachepchentry" aria-label="Permalink to &quot;`clore::extract::cache::CliceCachePCHEntry`&quot;">​</a></h3><p>Declaration: <code>extract/cache.cppm:51</code></p><p>Definition: <code>extract/cache.cppm:51</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/cache/"><code>Namespace clore::extract::cache</code></a></p><p><code>clore::extract::cache::CliceCachePCHEntry</code> 是一个仅包含数据的聚合体，用于持久化单个预编译头缓存条目。它的成员直接映射到磁盘上缓存的字段：<code>filename</code> 是 PCH 文件路径；<code>source_file</code> 是源文件索引；<code>hash</code> 是内容的校验和；<code>bound</code> 记录该 PCH 可覆盖的依赖边界计数器；<code>build_at</code> 是构建时间戳；<code>deps</code> 是一个 <code>std::vector&lt;CliceCacheDepEntry&gt;</code> 列表，记录该 PCH 所依赖的其它条目。该结构体没有用户定义的构造函数或特殊成员函数，依靠聚合初始化来设置所有字段，并且所有成员在初始化后均保持平凡的可复制语义。为保持缓存一致性，关键不变量包括：<code>hash</code> 必须与 <code>deps</code> 所对应的依赖图状态相匹配，且 <code>bound</code> 必须在同一缓存文件内的所有条目中单调递增。</p><h3 id="clore-extract-cache-clicecachepcmentry" tabindex="-1"><code>clore::extract::cache::CliceCachePCMEntry</code> <a class="header-anchor" href="#clore-extract-cache-clicecachepcmentry" aria-label="Permalink to &quot;`clore::extract::cache::CliceCachePCMEntry`&quot;">​</a></h3><p>Declaration: <code>extract/cache.cppm:60</code></p><p>Definition: <code>extract/cache.cppm:60</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/cache/"><code>Namespace clore::extract::cache</code></a></p><p>这是一个普通的聚合体，其所有数据成员均为公有。字段 <code>filename</code> 和 <code>module_name</code> 为 <code>std::string</code> 类型，分别存储 PCM 文件的路径和模块名称；<code>source_file</code> 和 <code>build_at</code> 被默认初始化为 <code>0</code>，分别用于引用源文件索引和记录构建时间戳；<code>deps</code> 是 <code>std::vector&lt;CliceCacheDepEntry&gt;</code> 类型的空向量，负责容纳该 PCM 条目的依赖项列表。该结构体没有自定义构造函数、析构函数或赋值运算符，完全依赖编译器生成的默认实现，因此不存在额外的运行时校验或资源管理逻辑。</p><h3 id="clore-extract-cache-dependencysnapshot" tabindex="-1"><code>clore::extract::cache::DependencySnapshot</code> <a class="header-anchor" href="#clore-extract-cache-dependencysnapshot" aria-label="Permalink to &quot;`clore::extract::cache::DependencySnapshot`&quot;">​</a></h3><p>Declaration: <code>extract/cache.cppm:29</code></p><p>Definition: <code>extract/cache.cppm:29</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/cache/"><code>Namespace clore::extract::cache</code></a></p><p>该结构体封装了构建时依赖项的快照，内部使用三个平行向量 <code>files</code>、<code>hashes</code> 和 <code>mtimes</code> 分别存储依赖项的文件路径、内容哈希值和最后修改时间。这三个向量的长度始终一致，构成隐式的不变量，任何修改操作都必须维护这一关系。<code>build_at</code> 记录快照生成时的单调时间戳（默认初始化为 <code>0</code>），用于后续判断快照是否已过时。所有成员均通过公共访问，但外部代码不应直接篡改向量长度的匹配性。</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-extract-cache-build-cache-key" tabindex="-1"><code>clore::extract::cache::build_cache_key</code> <a class="header-anchor" href="#clore-extract-cache-build-cache-key" aria-label="Permalink to &quot;`clore::extract::cache::build_cache_key`&quot;">​</a></h3><p>Declaration: <code>extract/cache.cppm:76</code></p><p>Definition: <code>extract/cache.cppm:228</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/cache/"><code>Namespace clore::extract::cache</code></a></p><p>函数 <code>clore::extract::cache::build_cache_key</code> 通过字符串拼接构造缓存键。它首先为目标字符串预留空间，大小为 <code>normalized_path</code> 的长度加 1（分隔符）再加 20（编译签数字符串的典型长度）。随后依次追加 <code>normalized_path</code>、常量 <code>kCacheKeyDelimiter</code> 以及通过 <code>std::to_string</code> 将 <code>compile_signature</code> 转换成的字符串。整个操作不涉及复杂控制流或其他外部依赖。</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>normalized_path</code></li><li><code>compile_signature</code></li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>returned <code>std::string</code></li></ul><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to build a key for caching extraction results based on a file path and a compile signature.</li></ul><h3 id="clore-extract-cache-build-compile-signature" tabindex="-1"><code>clore::extract::cache::build_compile_signature</code> <a class="header-anchor" href="#clore-extract-cache-build-compile-signature" aria-label="Permalink to &quot;`clore::extract::cache::build_compile_signature`&quot;">​</a></h3><p>Declaration: <code>extract/cache.cppm:74</code></p><p>Definition: <code>extract/cache.cppm:224</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/cache/"><code>Namespace clore::extract::cache</code></a></p><p>函数 <code>clore::extract::cache::build_compile_signature</code> 作为缓存层的入口，负责为传入的 <code>CompileEntry</code> 生成编译签名。其实现极为简洁：完全委托给非缓存计算函数 <code>clore::extract::build_compile_signature</code>，将 <code>entry</code> 原样转发。因此，该函数不包含自身算法或状态修改，仅作为适配器；实际签名计算、依赖关系和内部控制流全部交由下游函数处理，缓存层仅利用其返回值作为后续缓存键的组成部分。</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>entry</code> parameter (type <code>const CompileEntry&amp;</code>)</li></ul><h4 id="usage-patterns-6" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-6" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to generate a unique compile signature for cache key computation.</li><li>Called in caching logic to identify compile configurations.</li></ul><h3 id="clore-extract-cache-capture-dependency-snapshot" tabindex="-1"><code>clore::extract::cache::capture_dependency_snapshot</code> <a class="header-anchor" href="#clore-extract-cache-capture-dependency-snapshot" aria-label="Permalink to &quot;`clore::extract::cache::capture_dependency_snapshot`&quot;">​</a></h3><p>Declaration: <code>extract/cache.cppm:83</code></p><p>Definition: <code>extract/cache.cppm:282</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/cache/"><code>Namespace clore::extract::cache</code></a></p><p>该函数生成一个排序去重后的依赖文件快照，记录每个文件的路径、内容哈希和修改时间，并附上快照创建时间戳。首先对输入的文件路径列表进行规范化、排序与去重，然后依据硬件并发数分配并行任务。在每个工作线程中，对分配的文件依次获取文件状态（记录修改时间）并调用 <code>hash_file</code> 计算哈希值；若文件无法访问（如已被删除），则将哈希值置为 <code>0</code> 以标记变更，而非直接报错。所有线程完成后，若未出现错误，则将各线程的结果合并到 <code>DependencySnapshot</code> 的 <code>files</code>、<code>hashes</code> 和 <code>mtimes</code> 字段中，最终返回该快照。如果任一线程在早期检测到错误（由互斥锁保护的 <code>first_error</code> 指示），则提前返回该错误。</p><h4 id="side-effects-2" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-2" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-2" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-2" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>input parameter <code>files: const std::vector&lt;std::string&gt;&amp;</code></li><li>file content and metadata (via <code>hash_file</code> and <code>llvm::sys::fs::status</code>)</li></ul><h4 id="writes-to-1" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-1" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>returned <code>DependencySnapshot</code> object (local allocation and population)</li></ul><h4 id="usage-patterns-7" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-7" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called to capture dependency information for cache invalidation checks</li><li>used before comparing with a previous snapshot via <code>dependencies_changed</code></li></ul><h3 id="clore-extract-cache-dependencies-changed" tabindex="-1"><code>clore::extract::cache::dependencies_changed</code> <a class="header-anchor" href="#clore-extract-cache-dependencies-changed" aria-label="Permalink to &quot;`clore::extract::cache::dependencies_changed`&quot;">​</a></h3><p>Declaration: <code>extract/cache.cppm:86</code></p><p>Definition: <code>extract/cache.cppm:401</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/cache/"><code>Namespace clore::extract::cache</code></a></p><p><code>clore::extract::cache::dependencies_changed</code> 首先执行快速边界检查：当 <code>snapshot.build_at</code> 非正或 <code>snapshot.files</code> 为空，或 <code>files</code>、<code>hashes</code>、<code>mtimes</code> 三个容器大小不一致时，立即返回 <code>true</code> 表示依赖已变更。之后根据文件数量选择执行路径：若数量不超过 <code>kParallelThreshold</code>（16），则顺序遍历每个索引并调用 <code>check_single_dependency</code>；一旦发现变更即提前停止并返回 <code>true</code>，否则返回 <code>false</code>。</p><p>对于超过阈值的较大依赖集合，函数改用并行策略。它通过 <code>std::thread::hardware_concurrency()</code> 获取硬件线程数，构造至少一个线程。每个工作线程处理连续的索引子区间，并在循环中先检查 <code>changed</code> 原子标志（使用 <code>memory_order_relaxed</code>），若已检测到变更则立即返回；否则调用 <code>check_single_dependency</code> 检查当前依赖，一旦发现变更则置位 <code>changed</code> 并退出。主线程等待所有线程结束后返回 <code>changed</code> 的最终值。该实现通过细粒度的原子检查避免了不必要的计算，同时保持了对大集合的并行加速。</p><h4 id="side-effects-3" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-3" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-3" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-3" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>snapshot.build_at</code></li><li><code>snapshot.files</code></li><li><code>snapshot.hashes</code></li><li><code>snapshot.mtimes</code></li><li><code>std::thread::hardware_concurrency()</code></li></ul><h4 id="usage-patterns-8" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-8" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called before loading extract cache to determine freshness</li><li>used to decide whether to re-extract dependencies</li></ul><h3 id="clore-extract-cache-hash-file" tabindex="-1"><code>clore::extract::cache::hash_file</code> <a class="header-anchor" href="#clore-extract-cache-hash-file" aria-label="Permalink to &quot;`clore::extract::cache::hash_file`&quot;">​</a></h3><p>Declaration: <code>extract/cache.cppm:81</code></p><p>Definition: <code>extract/cache.cppm:270</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/cache/"><code>Namespace clore::extract::cache</code></a></p><p>该函数首先调用 <code>llvm::MemoryBuffer::getFile</code>，尝试以只读方式打开由 <code>path</code> 指定的文件。如果文件无法读取（例如不存在或无权限），函数立即返回 <code>std::unexpected&lt;CacheError&gt;</code>，其中错误信息包含原始系统错误的描述。若读取成功，则对得到的 <code>llvm::MemoryBuffer</code> 内容调用 <code>llvm::xxh3_64bits</code>，利用 XXH3 算法快速计算整个文件的 64 位哈希值，并将其作为成功结果返回。整个实现仅依赖 LLVM 的文件读取与哈希工具，不含任何外部状态或缓存逻辑。</p><h4 id="side-effects-4" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-4" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>reads from the file system via <code>llvm::MemoryBuffer::getFile</code></li><li>observable I/O: file read operation with potential latency and system calls</li></ul><h4 id="reads-from-4" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-4" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>parameter <code>path</code>: the file path to read</li><li>file content at <code>path</code></li></ul><h4 id="usage-patterns-9" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-9" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used by cache-key building functions to hash source files</li><li>called by <code>build_compile_signature</code> or <code>capture_dependency_snapshot</code> to incorporate file content into cache keys</li><li>part of the cache layer&#39;s file integrity verification</li></ul><h3 id="clore-extract-cache-load-clice-cache" tabindex="-1"><code>clore::extract::cache::load_clice_cache</code> <a class="header-anchor" href="#clore-extract-cache-load-clice-cache" aria-label="Permalink to &quot;`clore::extract::cache::load_clice_cache`&quot;">​</a></h3><p>Declaration: <code>extract/cache.cppm:95</code></p><p>Definition: <code>extract/cache.cppm:670</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/cache/"><code>Namespace clore::extract::cache</code></a></p><p><code>clore::extract::cache::load_clice_cache</code> 首先通过 <code>clice_cache_file_path</code> 将 <code>workspace_root</code> 转换为缓存的磁盘路径。若该路径对应的文件不存在（且无系统错误），立即返回一个空的 <code>CliceCacheData</code>；若存在系统错误则返回 <code>CacheError</code>。文件存在时，使用 <code>clore::support::read_utf8_text_file</code> 读取其全部文本内容，若读取失败同样返回错误。成功读取后，调用 <code>json::from_json</code> 将 JSON 内容反序列化为 <code>CliceCacheData</code>；若反序列化失败，函数记录一条警告并返回一个空的 <code>CliceCacheData</code>（视为缓存已过期），否则返回解析得到的 <code>data</code>。整个过程不修改外部状态，完全依赖于文件系统和 JSON 解析库。</p><h4 id="side-effects-5" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-5" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>performs filesystem existence check via <code>fs::exists</code></li><li>reads file content via <code>clore::support::read_utf8_text_file</code></li><li>logs a warning via <code>logging::warn</code> on JSON deserialization failure</li></ul><h4 id="reads-from-5" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-5" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>the clice cache file path derived from <code>workspace_root</code></li><li>the file system at that path</li><li>the content of the cache file</li></ul><h4 id="writes-to-2" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-2" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>logging subsystem (warning message)</li></ul><h4 id="usage-patterns-10" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-10" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>load cached clice data before extraction</li><li>check if a valid clice cache exists</li><li>used in pair with <code>save_clice_cache</code></li></ul><h3 id="clore-extract-cache-load-extract-cache" tabindex="-1"><code>clore::extract::cache::load_extract_cache</code> <a class="header-anchor" href="#clore-extract-cache-load-extract-cache" aria-label="Permalink to &quot;`clore::extract::cache::load_extract_cache`&quot;">​</a></h3><p>Declaration: <code>extract/cache.cppm:88</code></p><p>Definition: <code>extract/cache.cppm:457</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/cache/"><code>Namespace clore::extract::cache</code></a></p><p>函数 <code>clore::extract::cache::load_extract_cache</code> 通过以下流程从磁盘加载提取缓存：首先调用 <code>cache_file_path</code> 计算缓存文件路径，若文件不存在则直接返回空映射；若文件存在但读取失败或 JSON 反序列化失败，则记录警告并同样返回空映射。若 <code>SerializedCacheData</code> 中的 <code>format_version</code> 与 <code>kExtractCacheFormatVersion</code> 不匹配，也视为过期缓存而返回空映射。随后遍历 <code>data.entries</code>，对每个条目验证 <code>source_file</code> 索引是否越界，调用 <code>decode_dependency_snapshot</code> 将 <code>ast_deps</code> 解码为 <code>DependencySnapshot</code>，并使用 <code>normalize_path_string</code> 和 <code>build_cache_key</code> 构建缓存键，最终填充返回的 <code>std::unordered_map&lt;std::string, CacheRecord&gt;</code>。任何解码或索引错误都会导致返回 <code>std::unexpected&lt;CacheError&gt;</code>。</p><h4 id="side-effects-6" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-6" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>reads the extract cache file from disk</li><li>logs warnings via <code>logging::warn</code> when cache is stale or corrupted</li></ul><h4 id="reads-from-6" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-6" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>filesystem: cache file path derived from <code>workspace_root</code></li><li>parameter <code>workspace_root</code></li></ul><h4 id="writes-to-3" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-3" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>logging output via <code>logging::warn</code></li></ul><h4 id="usage-patterns-11" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-11" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called before extraction to check if a cached result exists</li><li>used in conjunction with <code>save_extract_cache</code> for read-write caching</li></ul><h3 id="clore-extract-cache-save-clice-cache" tabindex="-1"><code>clore::extract::cache::save_clice_cache</code> <a class="header-anchor" href="#clore-extract-cache-save-clice-cache" aria-label="Permalink to &quot;`clore::extract::cache::save_clice_cache`&quot;">​</a></h3><p>Declaration: <code>extract/cache.cppm:97</code></p><p>Definition: <code>extract/cache.cppm:710</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/cache/"><code>Namespace clore::extract::cache</code></a></p><p>该函数首先通过 <code>clice_cache_file_path</code> 解析出目标缓存文件路径 <code>cache_path</code>，并确保其父目录存在。随后调用 <code>json::to_json</code> 将 <code>CliceCacheData</code> 序列化为 JSON 字符串；若序列化失败则立即返回 <code>CacheError</code>。为了原子地写入缓存文件，函数采用“先写临时文件再重命名”的策略：利用 <code>llvm::xxh3_64bits</code> 对 <code>cache_path</code>、进程 ID <code>pid</code>、当前时间戳 <code>timestamp</code> 和重试序号 <code>attempt</code> 进行散列生成随机后缀，构造一个唯一的临时路径 <code>tmp_path</code>（最多尝试 32 次以避开已存在的文件）。通过 <code>clore::support::write_utf8_text_file</code> 将 JSON 内容写入 <code>tmp_path</code>。之后尝试将 <code>tmp_path</code> 重命名为 <code>cache_path</code>；若因权限不足、文件已存在或不允许操作等原因失败，则先尝试删除 <code>cache_path</code> 再重试一次重命名。所有文件系统操作均检查错误码并构造详细的 <code>CacheError</code> 返回。整个流程依赖 <code>clore::extract::cache</code> 内部的路径生成函数、JSON 序列化工具以及 filesystem 操作，并利用进程 ID 和单调时间戳确保临时文件唯一性，最终实现崩溃安全的缓存写入。</p><h4 id="side-effects-7" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-7" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Creates cache directories</li><li>Writes temporary file with unique name</li><li>Renames temporary file to final cache path</li><li>Removes existing cache file if rename fails due to permission or file exists</li></ul><h4 id="reads-from-7" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-7" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>workspace_root</code> parameter</li><li><code>data</code> parameter</li><li>system clock for timestamp</li><li>current process ID</li><li>filesystem state for existence checks</li></ul><h4 id="writes-to-4" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-4" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>cache directory</li><li>temporary cache file</li><li>final cache file</li></ul><h4 id="usage-patterns-12" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-12" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Persist clice extract cache</li><li>Called after extraction to update cache data</li></ul><h3 id="clore-extract-cache-save-extract-cache" tabindex="-1"><code>clore::extract::cache::save_extract_cache</code> <a class="header-anchor" href="#clore-extract-cache-save-extract-cache" aria-label="Permalink to &quot;`clore::extract::cache::save_extract_cache`&quot;">​</a></h3><p>Declaration: <code>extract/cache.cppm:91</code></p><p>Definition: <code>extract/cache.cppm:533</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/cache/"><code>Namespace clore::extract::cache</code></a></p><p>该函数首先通过 <code>cache_directory(workspace_root)</code> 获取缓存根目录，并创建该目录。随后构造 <code>SerializedCacheData</code>：遍历每条 <code>CacheRecord</code>，调用 <code>split_cache_key(file)</code> 拆解键并验证 <code>compile_signature</code> 是否匹配，然后使用 <code>intern_path</code> 闭包对路径字符串进行标准化并分配 ID，将记录字段转换为 <code>SerializedCacheEntry</code>，其中依赖快照通过 <code>encode_dependency_snapshot</code> 序列化。全部记录填充至 <code>data</code> 后，调用 <code>json::to_json</code> 序列化为 JSON 字符串。</p><p>为确保写入原子性，函数在目标 <code>cache_path</code> 所在目录下生成唯一临时文件路径：循环最多 32 次，每次基于当前时间戳、进程 PID 和递增尝试号，通过 <code>llvm::xxh3_64bits</code> 计算随机数构造候选路径，直到 <code>fs::exists</code> 检测该路径不存在。将序列化内容通过 <code>clore::support::write_utf8_text_file</code> 写入临时文件。最后使用 <code>fs::rename</code> 将临时文件原子地移动到 <code>cache_path</code>；若因权限或文件存在错误导致重命名失败，则先删除目标文件再重试。整个过程中任何文件系统错误都会返回带有描述信息的 <code>CacheError</code>。</p><h4 id="side-effects-8" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-8" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Creates cache directory if it does not exist</li><li>Writes a temporary JSON file to the filesystem</li><li>Atomically renames the temporary file to the final cache path</li><li>May remove an existing cache file before rename on permission or file-exists errors</li></ul><h4 id="reads-from-8" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-8" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>workspace_root</code> parameter</li><li><code>records</code> parameter (a map of file paths to <code>CacheRecord</code>)</li><li>Filesystem: checks existence of temporary file candidates</li><li>System clock for timestamp</li><li>Process ID via <code>llvm::sys::Process::getProcessId</code></li></ul><h4 id="writes-to-5" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-5" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>Filesystem: cache directory under <code>workspace_root</code></li><li>Filesystem: <code>cache.json</code> file inside cache directory</li><li>Filesystem: temporary files with <code>.tmp</code> extension</li></ul><h4 id="usage-patterns-13" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-13" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called to persist extract cache after a successful extraction pass</li><li>Used to store incremental build cache for later reuse</li></ul><h3 id="clore-extract-cache-split-cache-key" tabindex="-1"><code>clore::extract::cache::split_cache_key</code> <a class="header-anchor" href="#clore-extract-cache-split-cache-key" aria-label="Permalink to &quot;`clore::extract::cache::split_cache_key`&quot;">​</a></h3><p>Declaration: <code>extract/cache.cppm:79</code></p><p>Definition: <code>extract/cache.cppm:238</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/cache/"><code>Namespace clore::extract::cache</code></a></p><p>函数 <code>clore::extract::cache::split_cache_key</code> 的核心算法是解析缓存键字符串。它首先使用 <code>std::string_view::rfind</code> 查找 <code>kCacheKeyDelimiter</code> 在输入 <code>cache_key</code> 中的最后一次出现位置；若未找到，则立即返回一个带有描述性消息的 <code>CacheError</code>。找到分隔符后，函数将字符串分割为 <code>path_part</code> 和 <code>signature_part</code> 两个子串，并对两者进行非空校验。随后，利用 <code>std::from_chars</code> 将 <code>signature_part</code> 解析为 <code>std::uint64_t</code> 类型的 <code>signature</code>，并检查解析是否完全消耗了整个子串。任一验证失败都会导致返回 <code>CacheError</code>。解析成功后，构造并返回 <code>CacheKeyParts</code> 对象，其 <code>path</code> 字段取自 <code>path_part</code> 的拷贝，<code>compile_signature</code> 字段为解析得到的 <code>signature</code>。该函数的实现完全依赖于 <code>kCacheKeyDelimiter</code> 常量的定义、<code>CacheKeyParts</code> 和 <code>CacheError</code> 的数据结构，以及 <code>std::from_chars</code> 的标准库功能。</p><h4 id="side-effects-9" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-9" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-9" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-9" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>The input parameter <code>cache_key</code> of type <code>std::string_view</code></li><li>The constant <code>kCacheKeyDelimiter</code></li></ul><h4 id="usage-patterns-14" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-14" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Parsing cache keys previously built by <code>build_cache_key</code></li><li>Extracting path and signature before cache lookup operations</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p>模块 <code>extract:cache</code> 是提取流水线中专司缓存持久化与失效检测的内层组件，其外部接口与内部实现严格分离。公共 API 层提供键值构造（<code>build_cache_key</code>、<code>build_compile_signature</code>、<code>split_cache_key</code>）、文件哈希（<code>hash_file</code>）、依赖快照捕获与比较（<code>capture_dependency_snapshot</code>、<code>dependencies_changed</code>）以及针对提取结果与 Clice 缓存结构的存取操作（<code>load_extract_cache</code>/<code>save_extract_cache</code>、<code>load_clice_cache</code>/<code>save_clice_cache</code>）。这些函数依赖 <code>support</code> 模块的路径归一化、签名计算等基础工具，并通过模块导入（<code>extract:ast</code>、<code>extract:compiler</code>、<code>extract:scan</code>）获得上游提取与扫描数据结构，从而将编译产物与中间结果关联到唯一的缓存条目。</p><p>在内部实现上，模块通过匿名命名空间封装了序列化结构体（如 <code>SerializedCacheData</code>、<code>SerializedCacheEntry</code>、<code>SerializedDependencySnapshot</code>）、缓存路径解析以及依赖快照的编码/解码逻辑。并发哈希捕获采用线程池（<code>per_thread</code> 变量）与阈值（<code>kParallelThreshold</code>）控制，通过 <code>DependencyHashTaskResult</code> 收集并行任务结果；所有 I/O 操作（文件创建、重命名、删除）均经由原子写入（临时文件→重命名）策略保证缓存的文件级一致性。这种分层结构使得缓存管理逻辑独立于上层提取算法，仅通过清晰的公共接口和内部辅助函数完成数据的序列化、校验与失效判定。</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./ast">Module extract:ast</a></li><li><a href="./compiler">Module extract:compiler</a></li><li><a href="./scan">Module extract:scan</a></li><li><a href="./../support/">Module support</a></li></ul>',207)])])}const m=c(r,[["render",d]]);export{u as __pageData,m as default};
